```swift
class CartManager {
    private let service: CartAPIService
    private var currentCartID: Int64?

    init(service: CartAPIService) {
        self.service = service
    }

    func addItemToCart(id: Int64, completion: @escaping (String?) -> ()) {
        service.addItemToCart(id: id) { error in
            if let error = error as? CartAPIServiceError {
                completion(error.errorMessage)
                return
            }
            self.currentCartID = id
            completion(nil)
        }
    }

    func removeItemFromCart(id: Int64, completion: @escaping (String?) -> ()) {
        service.removeItemFromCart(id: id) { error in
            if let error = error as? CartAPIServiceError {
                completion(error.errorMessage)
                return
            }
            completion(nil)
        }
    }
}
```

