def bundle_assets(input_files, filters, output_files):
    bundled_content = {}
    for asset_type, files in input_files.items():
        content = ""
        for file in files:
            with open(file, 'r') as f:
                content += f.read()
        for filter_name in filters.get(asset_type, []):
            content = apply_filter(content, filter_name)
        bundled_content[asset_type] = content
        with open(output_files[asset_type], 'w') as f:
            f.write(content)
