import gym
import numpy as np

class QLearningAgent:
    def __init__(self, env_name=DEFAULT_ENV_NAME, learning_rate=DEFAULT_LEARNING_RATE, gamma=DEFAULT_GAMMA):
        self.env = gym.make(env_name)
        self.learning_rate = learning_rate
        self.gamma = gamma
        self.q_table = np.zeros((self.env.observation_space.n, self.env.action_space.n))

    def choose_action(self, state, epsilon=0.1):
        if np.random.uniform(0, 1) < epsilon:
            return self.env.action_space.sample()  # Explore action space
        else:
            return np.argmax(self.q_table[state, :])  # Exploit learned values

    def update_q_table(self, state, action, reward, next_state):
        self.q_table[state, action] += self.learning_rate * (reward + self.gamma * np.max(self.q_table[next_state, :]) - self.q_table[state, action])

    def train(self, max_episodes=DEFAULT_MAX_EPISODES):
        for episode in range(max_episodes):
            state = self.env.reset()
            done = False
            while not done:
                action = self.choose_action(state)
                next_state, reward, done, _ = self.env.step(action)
                self.update_q_table(state, action, reward, next_state)
                state = next_state
```

This solution provides a QLearningAgent class that implements the Q-learning algorithm to train an agent to solve the CartPole-v1 environment. The agent initializes the Q-table, chooses actions based on epsilon-greedy policy, updates the Q-values, and trains the agent through episodes using the provided default parameters.

