```python
from typing import List, Dict

def filter_messages(messages: List[Dict[str, Dict[str, str]]]) -> List[Dict[str, Dict[str, str]]]:
    filtered = []
    for message in messages:
        if message.get('message').get('from').get('username') == 'devbot' and 'urgent' in message.get('message').get('text').lower():
            filtered.append(message)
    return filtered
