public int countPackageDeclarations(String sourceCode) {
    int count = 0;
    String[] lines = sourceCode.split("\n");
    for (String line : lines) {
        String trimmedLine = line.trim();
        if (trimmedLine.startsWith("package ")) {
            count++;
        }
