import heapq

class Graph:
    def __init__(self, num_vertices):
        self.num_vertices = num_vertices
        self.adj_matrix = [[float('inf')]*num_vertices for _ in range(num_vertices)]

    def add_edge(self, i, j, distance, time):
        self.adj_matrix[i][j] = distance, time
        self.adj_matrix[j][i] = distance, time

    def get_shortest_distances(self, start_vertex):
        distances = [float('inf')]*self.num_vertices
        distances[start_vertex] = (0, 0)

        pq = [(0, start_vertex)]  # priority queue

        while pq:
            curr_distance, curr_vertex = heapq.heappop(pq)

            if distances[curr_vertex] < (curr_distance):
                continue

            for neighbor in range(self.num_vertices):
                distance, time = self.adj_matrix[curr_vertex][neighbor]
                
                if distance == float('inf'):
                    continue
                
                if curr_distance + distance < distances[neighbor][0]:
                    distances[neighbor] = (curr_distance + distance, curr_distance + time)
                    heapq.heappush(pq, (distances[neighbor][0], neighbor))

        return distances


def main():
    num_cities = 5

    # input roads and distances between cities
    graph = Graph(num_cities)

    for i in range(num_cities - 1):
        for j in range(i + 1, num_cities):
            print(f"Enter distance and time between city {i+1} and city {j+1}:")
            distance = int(input())
            time = int(input())
            graph.add_edge(i, j, distance, time)

    # get shortest distances and times for each mode of transportation from the starting city
    start_city = int(input("Enter the starting city (1-5): ")) - 1
    
    for mode in ["car", "bike", "walk"]:
        print(f"\nShortest distance and time by {mode} from city {start_city+1}:")

        distances = graph.get_shortest_distances(start_city)
        for i in range(num_cities):
            distance, time = distances[i]
            if mode == "car":
                time = distance / 60  # convert distance to minutes
            elif mode == "bike":
                time = distance / 15
            elif mode == "walk":
                time = distance / 5
            print(f"City {i+1}: distance = {distance}, time = {time:.2f} minutes")

    # get shortest distances and times for a specific mode of transportation from the starting city
    mode = input("Enter preferred mode of transportation (car/bike/walk): ")
    print(f"\nShortest distance and time by {mode} from city {start_city+1}:")
    distances = graph.get_shortest_distances(start_city)
    for i in range(num_cities):
        distance, time = distances[i]
        if mode == "car":
            time = distance / 60  # convert distance to minutes
        elif mode == "bike":
            time = distance / 15
        elif mode == "walk":
            time = distance / 5
        print(f"City {i+1}: distance = {distance}, time = {time:.2f} minutes")


if __name__ == '__main__':
    main()
```

