// Define the GMs type representing the result of the command execution
type GMs = Result<(), ()>;

// Define the Effect enum with a variant GCmd that holds a boxed generic command
enum Effect<C>
where
    C: Future<Item = GMs, Error = GMs> + 'static,
{
    GCmd(Box<C>),
}

// Define the CommandExecutor struct with a VecDeque field named effects to store the effects
struct CommandExecutor {
    effects: VecDeque<Effect<Box<dyn Future<Item = GMs, Error = GMs> + 'static>>>,
}

impl CommandExecutor {
    // Implement the add_command method for the CommandExecutor struct
    fn add_command<C>(&mut self, g_cmd: C) -> &Self
    where
        C: Future<Item = GMs, Error = GMs> + 'static,
    {
        let effect = Effect::GCmd(Box::new(g_cmd));
        self.effects.push_back(effect);
        self
    }
}
```

