interface InternalValidationResult {
  key: string;
  message: string;
  type: string;
  succeeded: boolean;
  arrayErrors: { [fieldName: string]: { succeeded: boolean; message: string; type: string } }[];
}

interface MappedValidationResult {
  key: string;
  message: string;
  type: string;
  succeeded: boolean;
  arrayErrors: { fieldName: string; validationType: string; validationMessage: string }[];
}

function mapValidationResult(internalValidationResult: InternalValidationResult): MappedValidationResult {
  const mappedResult: MappedValidationResult = {
    key: internalValidationResult.key,
    message: internalValidationResult.message,
    type: internalValidationResult.type,
    succeeded: internalValidationResult.succeeded,
    arrayErrors: [],
  };

  internalValidationResult.arrayErrors.forEach((error) => {
    Object.keys(error).forEach((fieldName) => {
      const { succeeded, message, type } = error[fieldName];
      mappedResult.arrayErrors.push({
        fieldName,
        validationType: type,
        validationMessage: message,
      });
    });
  });

  return mappedResult;
}

