    // Exclude these properties from deserialization
    [JsonIgnore]
    public DateTime CreatedAt { get; set; }

    [JsonIgnore]
    public DateTime UpdatedAt { get; set; }
}
```

2. If the JSON string has varying property names, we can use the [JsonExtensionData] attribute to include all properties that are not explicitly mapped to properties in the class. We can store them in a Dictionary<string, JToken> property. For example:

```csharp
public class MyData {
    [JsonProperty("id")]
    public int Id { get; set; }

    [JsonProperty("name")]
    public string Name { get; set; }

    [JsonProperty("value")]
    public double Value { get; set; }

    [JsonProperty("nested")]
