    // Exclude these properties from deserialization
    [JsonIgnore]
    public DateTime CreatedAt { get; set; }

    [JsonIgnore]
    public DateTime UpdatedAt { get; set; }

    // Include all properties that are not explicitly mapped
    [JsonExtensionData]
    public Dictionary<string, JToken> AdditionalData { get; set; }
}
```

3. To exclude specific properties from deserialization, we can use the [JsonIgnore] attribute to mark those properties in the class. For example:

```csharp
public class MyData {
    [JsonProperty("id")]
