    [JsonIgnore]
    public DateTime UpdatedAt { get; set; }

    // Include all properties that are not explicitly mapped
    [JsonExtensionData]
    public Dictionary<string, JToken> AdditionalData { get; set; }

    // New properties in the modified JSON string
    [JsonProperty("Tag")]
    public string Tag { get; set; }

    [JsonProperty("TotalTime")]
    public int TotalTime { get; set; }
}
```

4. To deserialize the JSON string, we can use the JsonConvert.DeserializeObject<T> method from the Newtonsoft.Json library. For example:

```csharp
