class PreConditionError(Exception):
    pass

def pre(condition):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if not condition(*args, **kwargs):
                raise PreConditionError("Precondition not met")
            return func(*args, **kwargs)
        return wrapper
    return decorator

