func main() {
	// initialize database
	var err error
	db, err = sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/database")
	if err != nil {
		log.Fatalf("Error opening database: %v", err)
	}
	defer db.Close()

	// initialize http server
	http.HandleFunc("/", handler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func handler(w http.ResponseWriter, r *http.Request) {
	// authenticate request
	err := authenticateRequest(r)
	if err != nil {
		log.Printf("Authentication failed for %s: %v", r.RemoteAddr, err)
		http.Error(w, http.StatusText(http.StatusUnauthorized), http.StatusUnauthorized)
		return
	}

	// return public ip address
	ip := strings.Split(r.RemoteAddr, ":")[0]
	fmt.Fprintf(w, "Public IP Address: %s\n", ip)
}

func authenticateRequest(r *http.Request) error {
	// read request body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return err
	}

	// decrypt request body
	plaintext, err := decryptRequest(body)
	if err != nil {
		return err
	}

	// unmarshal request body
	var req authRequest
	err = json.Unmarshal(plaintext, &req)
	if err != nil {
		return err
	}

	// verify ip address in request matches authorized ips
	ip := strings.Split(r.RemoteAddr, ":")[0]
	for _, authorizedIP := range req.IPs {
		if ip == authorizedIP {
			// log successful authentication
			err := logAuthAttempt(r.RemoteAddr, true)
			if err != nil {
				log.Printf("Error logging authentication attempt: %v", err)
			}
			return nil
		}
	}

	// log failed authentication
	err = logAuthAttempt(r.RemoteAddr, false)
	if err != nil {
		log.Printf("Error logging authentication attempt: %v", err)
	}

	return errors.New("Unauthorized IP address")
}

func decryptRequest(ciphertext []byte) ([]byte, error) {
	// generate 32 byte key from authKey using sha256
	key := sha256.Sum256([]byte(authKey))

	// decode base64 encoded ciphertext
	ciphertext, err := base64.StdEncoding.DecodeString(string(ciphertext))
	if err != nil {
		return nil, err
	}

	// extract iv from ciphertext
	iv := ciphertext[:aes.BlockSize]
	ciphertext = ciphertext[aes.BlockSize:]

	// initialize aes block cipher
	block, err := aes.NewCipher(key[:])
	if err != nil {
		return nil, err
	}

	// initialize cipher block chaining mode with aes and iv
	mode := cipher.NewCBCDecrypter(block, iv)

	// decrypt ciphertext
	mode.CryptBlocks(ciphertext, ciphertext)

	// unpad plaintext
	return unpad(ciphertext)
}

func logAuthAttempt(remoteAddr string, success bool) error {
	// insert authentication attempt into database
	_, err := db.Exec("INSERT INTO auth_attempts(remote_addr, success, time) VALUES (?, ?, ?)", remoteAddr, success, time.Now().Unix())
	if err != nil {
		return err
	}

	return nil
}

func unpad(src []byte) ([]byte, error) {
	length := len(src)
	if length == 0 {
		return nil, errors.New("src is empty")
	}

	padding := int(src[length-1])

	if padding > length || padding > aes.BlockSize {
		return nil, errors.New("invalid padding")
	}

	for i := 0; i < padding; i++ {
		if int(src[length-1-i]) != padding {
			return nil, errors.New("invalid padding")
		}
	}

	return src[:length-padding], nil
}

func pad(src []byte) ([]byte, error) {
	blockSize := aes.BlockSize

	padLen := blockSize - (len(src) % blockSize)

	padding := make([]byte, padLen)
	if _, err := rand.Read(padding); err != nil {
		return nil, err
	}

	padding[padLen-1] = byte(padLen)

	return append(src, padding...), nil
}
