import os
import sys

def create_config_symlink(target_file_path):
    config_dir = os.path.expanduser("~/.config/nvim")

    # Create the ~/.config/nvim directory if it doesn't exist
    if not os.path.exists(config_dir):
        os.makedirs(config_dir)

    # Construct the path for the symbolic link
    symlink_path = os.path.join(config_dir, os.path.basename(target_file_path))

    try:
        # Create the symbolic link
        os.symlink(target_file_path, symlink_path)
        print(f"Symbolic link created for {target_file_path} in {config_dir}")
    except FileExistsError:
        print(f"Symbolic link already exists for {target_file_path} in {config_dir}")
    except FileNotFoundError:
        print(f"Error: {target_file_path} does not exist")
    except PermissionError:
        print("Error: Permission denied. Try running the command with elevated privileges")

if __name__ == "__main__":
    if len(sys.argv) != 3 or sys.argv[1] != "config":
        print("Usage: dotlink config <target_file_path>")
    else:
        create_config_symlink(sys.argv[2])
