public class MenuItem
{
    public string Name { get; set; }
    public List<MenuItem> SubMenuItems { get; set; }

    public MenuItem(string name)
    {
        Name = name;
        SubMenuItems = new List<MenuItem>();
    }
}

public class MenuSystem
{
    private List<MenuItem> topMenuItems;

    public MenuSystem()
    {
        topMenuItems = new List<MenuItem>();
    }

    public void AddTopMenuItem(string name)
    {
        topMenuItems.Add(new MenuItem(name));
    }

    public void AddSubMenuItem(string topLevelName, string subMenuName)
    {
        MenuItem topLevelItem = topMenuItems.Find(item => item.Name == topLevelName);
        if (topLevelItem != null)
        {
            topLevelItem.SubMenuItems.Add(new MenuItem(subMenuName));
        }
        else
        {
            throw new ArgumentException("Top-level menu item not found.");
        }
    }

    public void RemoveMenuItem(string name)
    {
        MenuItem menuItem = topMenuItems.Find(item => item.Name == name);
        if (menuItem != null)
        {
            topMenuItems.Remove(menuItem);
        }
        else
        {
            throw new ArgumentException("Menu item not found.");
        }
    }

    public MenuItem GetMenuItem(string name)
    {
        return topMenuItems.Find(item => item.Name == name);
    }

    public void DisplayMenuHierarchy()
    {
        foreach (var item in topMenuItems)
        {
            Console.WriteLine(item.Name);
            DisplaySubMenuItems(item.SubMenuItems, 1);
        }
    }

    private void DisplaySubMenuItems(List<MenuItem> subMenuItems, int level)
    {
        foreach (var item in subMenuItems)
        {
            Console.WriteLine(new string('-', level * 2) + item.Name);
            DisplaySubMenuItems(item.SubMenuItems, level + 1);
        }
    }
}

