def extract_instance_id(sample: str) -> str:
    if not sample:
        return "Sample string is empty"

    hyphen_index = sample.find("-")
    if hyphen_index == -1:
        return "No instance ID found"

    for i in range(hyphen_index + 1, len(sample)):
