func parseTestItems(from jsonData: Data) throws -> [TestItem] {
    let json = try JSON(data: jsonData)
    var testItems: [TestItem] = []

    if let passedTests = json["PassedTests"]["Test"].array {
        for testJSON in passedTests {
            let testItem = try TestItem(jsonData: testJSON)
            testItem.status = "Passed"
            testItems.append(testItem)
        }
    }

    if let failedTests = json["FailedTests"]["Test"].array {
        for testJSON in failedTests {
            let testItem = try TestItem(jsonData: testJSON)
            testItem.status = "Failed"
            testItems.append(testItem)
        }
    }

    if let skippedTests = json["SkippedTests"]["Test"].array {
        for testJSON in skippedTests {
            let testItem = try TestItem(jsonData: testJSON)
            testItem.status = "Skipped"
            testItems.append(testItem)
        }
    }

    return testItems
}
