```

Example:
```javascript
const options = {
  x: true,
  y: false,
  minHeight: 5,
  minWidth: 3
};

console.log(calculateRectangleArea(6, 4, options)); // Output: 24
console.log(calculateRectangleArea(2, 7, options)); // Output: 14
```

```javascript
function calculateRectangleArea(height, width, options) {
  const { x, y, minHeight, minWidth } = { ...defaultOptions, ...options };

  const effectiveHeight = Math.max(height, minHeight);
  const effectiveWidth = Math.max(width, minWidth);

  if (x && y) {
    return effectiveHeight * effectiveWidth;
  } else if (x) {
    return effectiveWidth * effectiveHeight;
  } else if (y) {
    return effectiveHeight * effectiveWidth;
  } else {
    return effectiveWidth * effectiveHeight;
  }
}
```

