import os

def count_file_extensions(file_paths):
    file_extension_count = {}
    for file_path in file_paths:
        try:
            _, file_extension = os.path.splitext(file_path)
            if file_extension:
                file_extension = file_extension[1:].lower()  # Remove the dot and convert to lowercase
                file_extension_count[file_extension] = file_extension_count.get(file_extension, 0) + 1
        except IOError:
            pass  # Skip problematic file paths
    return file_extension_count
